    A -->|1. 开始迭代| D
    A -->|2. 创建迭代记录| E
    A -->|3. 推送实时事件| F
    F -->|4. 广播| H
    E -->|5. 持久化| G
    B --> C
```

### 2. 核心改进点

#### **改进点 1：AutoIterationEngine 添加 Dashboard 集成**

**当前问题：**
```typescript
// ❌ 当前代码：没有与 Dashboard 通信
export class AutoIterationEngine {
  async start() {
    // 直接运行 Agent，没有通知 Dashboard
    await this.runAgent('architect', '设计架构');
  }
}
```

**改进方案：**
```typescript
// ✅ 改进后：集成 Dashboard 服务
export class AutoIterationEngine {
  private dashboardServices: any = null;

  async initDashboard() {
    try {
      const { getServices } = await import('./dashboard/server');
      this.dashboardServices = getServices();
      console.log('✅ Dashboard services loaded');
    } catch (error) {
      console.log('⚠️ Dashboard not available, running standalone');
    }
  }

  async start() {
    await this.initDashboard();

    // 1. 创建迭代记录
    if (this.dashboardServices?.iterationService) {
      const iteration = await this.dashboardServices.iterationService.create({
        iterationNumber: this.iterationCount,
        status: 'running',
        requirement: this.currentTask,
        startedAt: new Date()
      });

      this.currentIterationId = iteration.id;
    }

    // 2. 推送开始事件
    await this.broadcastEvent('iteration.started', {
      iterationNumber: this.iterationCount,
      requirement: this.currentTask
    });

    // 3. 执行产品经理
    await this.runAgent('productManager', '分析需求');

    // 4. 执行架构师
    await this.runAgent('architect', '设计架构');
  }

  private async runAgent(agentName: string, task: string) {
    // 推送 Agent 开始
    await this.broadcastEvent('agent.started', {
      agentName,
      task,
      startTime: new Date()
    });

    try {
      const result = await this.agents[agentName].executeAndCollect(task);

      // 推送 Agent 完成
      await this.broadcastEvent('agent.completed', {
        agentName,
        status: 'completed',
        result: result.substring(0, 200)
      });

      return result;
    } catch (error) {
      // 推送错误
      await this.broadcastEvent('agent.failed', {
        agentName,
        error: error.message
      });
      throw error;
    }
  }

  private async broadcastEvent(event: string, data: any) {
    if (this.dashboardServices?.realtimeService) {
      await this.dashboardServices.realtimeService.broadcast({
        event,
        data,
        timestamp: new Date()
      });
    }
  }
}
```

---

#### **改进点 2：增强的 WebSocket 事件类型**

**新增事件：**

```typescript
// src/dashboard/types.ts
export type DashboardEvent =
  | { event: 'iteration.started'; data: { iterationNumber: number; requirement: string } }
  | { event: 'iteration.completed'; data: { iterationNumber: number; duration: number } }
  | { event: 'iteration.failed'; data: { iterationNumber: number; error: string } }
  | { event: 'agent.started'; data: { agentName: string; task: string; startTime: Date } }
  | { event: 'agent.completed'; data: { agentName: string; status: string; result: string } }
  | { event: 'agent.failed'; data: { agentName: string; error: string } }
  | { event: 'agent.progress'; data: { agentName: string; progress: number; currentTask: string } }
  | { event: 'system.metrics'; data: { cpu: number; memory: number; timestamp: Date } };
```

