#### **改进点 3：验证和测试**

**测试脚本：**

```typescript
// tests/integration/dashboard-auto-iteration.test.ts
import { describe, it, expect, beforeAll, afterAll } from '@jest/globals';
import { AutoIterationEngine } from '../../src/auto-iteration';
import { startDashboard, getServices } from '../../src/dashboard/server';

describe('Dashboard Integration', () => {
  let dashboard: any;
  let engine: AutoIterationEngine;

  beforeAll(async () => {
    // 启动 Dashboard
    dashboard = await startDashboard();

    // 等待服务就绪
    await new Promise(resolve => setTimeout(resolve, 1000));
  });

  it('should create iteration record when starting', async () => {
    const { iterationService } = getServices();
    const beforeCount = iterationService.getList({ page: 1, limit: 100 }).total;

    engine = new AutoIterationEngine({
      projectPath: process.cwd(),
      intervalMs: 60000,
      maxIterations: 1,
      autoCommit: false,
      autoPush: false
    });

    await engine.start();

    const afterCount = iterationService.getList({ page: 1, limit: 100 }).total;
    expect(afterCount).toBe(beforeCount + 1);
  });

  it('should broadcast events via WebSocket', (done) => {
    const WebSocket = require('ws');
    const ws = new WebSocket('ws://localhost:3000/api/ws');

    ws.on('open', () => {
      engine.start();
    });

    ws.on('message', (data) => {
      const message = JSON.parse(data);
      if (message.event === 'iteration.started') {
        expect(message.data).toHaveProperty('iterationNumber');
        ws.close();
        done();
      }
    });
  });

  afterAll(async () => {
    if (dashboard) {
      await dashboard.close();
    }
  });
});
```

